import numpy as np
from collections import Counter, defaultdict
import math

class BM25F:
    def __init__(self, fields_config: dict, k1: float = 1.5):
        self.fields_config = fields_config
        self.k1 = k1
        self.corpus = None
        self.doc_tfs = None       # list of {field: Counter}
        self.doc_lens = None      # {field: list of lengths}
        self.avgdl = None         # {field: avg length}
        self.df = None            # term -> document frequency (across any field)
        self.idf = None
        self.N = 0

    def fit(self, corpus: list) -> 'BM25F':
        self.corpus = corpus
        self.N = len(corpus)
        self.doc_tfs = []
        self.doc_lens = defaultdict(list)

        df = Counter()
        for doc in corpus:
            doc_field_tfs = {}
            doc_terms_seen = set()
            for field in self.fields_config:
                tokens = doc.get(field, [])
                tf = Counter(tokens)
                doc_field_tfs[field] = tf
                self.doc_lens[field].append(len(tokens))
                doc_terms_seen.update(tokens)
            self.doc_tfs.append(doc_field_tfs)
            df.update(doc_terms_seen)

        self.avgdl = {
            field: (sum(lens) / len(lens) if lens else 1.0)
            for field, lens in self.doc_lens.items()
        }
        self.df = df
        self.idf = {
            term: math.log((self.N - count + 0.5) / (count + 0.5) + 1)
            for term, count in df.items()
        }
        return self

    def _pseudo_tf(self, term, doc_idx):
        doc_field_tfs = self.doc_tfs[doc_idx]
        ptf = 0.0
        for field, config in self.fields_config.items():
            tf = doc_field_tfs.get(field, Counter()).get(term, 0)
            if tf == 0:
                continue
            avg = self.avgdl.get(field, 1.0)
            dl = self.doc_lens[field][doc_idx]
            b = config['b']
            w = config['weight']
            norm = 1 - b + b * dl / (avg if avg > 0 else 1.0)
            ptf += w * tf / norm
        return ptf

    def score(self, query: list, top_k: int = 10) -> list:
        query_terms = set(query)
        results = []
        for doc_idx in range(self.N):
            s = 0.0
            for term in query_terms:
                if term not in self.idf:
                    continue
                ptf = self._pseudo_tf(term, doc_idx)
                if ptf == 0:
                    continue
                idf = self.idf[term]
                s += idf * ptf / (self.k1 + ptf)
            if s > 0:
                results.append((doc_idx, s))
        results.sort(key=lambda x: -x[1])
        return results[:top_k]

