fields = {'title': {'weight': 2.0, 'b': 0.5}, 'body': {'weight': 1.0, 'b': 0.75}}
bm25f = BM25F(fields)
corpus = [
    {'title': ['machine', 'learning'], 'body': ['neural', 'networks']},
    {'title': ['deep', 'learning'], 'body': ['machine', 'learning', 'methods']}
]
bm25f.fit(corpus)
results = bm25f.score(['learning'], top_k=2)
for doc_idx, score in results:
    assert score > 0, f"Matching docs must have positive scores, got {score}"
